1	// Session Policy:
2	// - Hard max lifetime: 24 hours (expires_at in DB, cookie maxAge)
3	// - Inactivity timeout: 8 hours (last_activity_at checked on each request)
4	// - last_activity_at is refreshed on every authenticated request
5	
6	import { query } from '../db/pool.js';
7	import { Errors } from '../utils/errors.js';
8	import { hashToken } from '../utils/crypto.js';
9	
10	export const SESSION_TIMEOUT_HOURS = 8;
11	
12	export async function authenticate(request, reply) {
13	  const token = request.cookies?.petmed_session;
14	  if (!token) {
15	    throw Errors.authRequired();
16	  }
17	
18	  const tokenHash = hashToken(token);
19	  const result = await query(
20	    `SELECT s.id as session_id, s.user_id, s.expires_at, s.last_activity_at,
21	            u.username, u.display_name, u.status as user_status
22	     FROM sessions s
23	     JOIN users u ON u.id = s.user_id
24	     WHERE s.token_hash = $1 AND s.expires_at > NOW()`,
25	    [tokenHash]
26	  );
27	
28	  if (result.rows.length === 0) {
29	    throw Errors.authRequired();
30	  }
31	
32	  const session = result.rows[0];
33	  if (session.user_status !== 'active') {
34	    throw Errors.authRequired();
35	  }
36	
37	  const lastActivity = new Date(session.last_activity_at);
38	  const inactivityLimit = new Date(lastActivity.getTime() + SESSION_TIMEOUT_HOURS * 60 * 60 * 1000);
39	  if (new Date() > inactivityLimit) {
40	    await query('DELETE FROM sessions WHERE id = $1', [session.session_id]);
41	    throw Errors.authRequired();
42	  }
43	
44	  await query(
45	    'UPDATE sessions SET last_activity_at = NOW() WHERE id = $1',
46	    [session.session_id]
47	  );
48	
49	  const rolesResult = await query(
50	    `SELECT r.name, r.permissions FROM roles r
51	     JOIN user_roles ur ON ur.role_id = r.id
52	     WHERE ur.user_id = $1`,
53	    [session.user_id]
54	  );
55	
56	  const scopesResult = await query(
57	    'SELECT scope_type, scope_id FROM user_scopes WHERE user_id = $1',
58	    [session.user_id]
59	  );
60	
61	  const roles = rolesResult.rows.map(r => r.name);
62	  const permissions = rolesResult.rows.flatMap(r => r.permissions || []);
63	  const scopes = scopesResult.rows;
64	
65	  request.user = {
66	    id: session.user_id,
67	    username: session.username,
68	    display_name: session.display_name,
69	    roles,
70	    permissions,
71	    scopes,
72	    sessionId: session.session_id,
73	  };
74	}
75	
76	export function requirePermission(...requiredPerms) {
77	  return async (request, reply) => {
78	    if (!request.user) throw Errors.authRequired();
79	    const userPerms = request.user.permissions;
80	    const hasAdmin = userPerms.some(p => p === 'admin.*');
81	    if (hasAdmin) return;
82	
83	    for (const perm of requiredPerms) {
84	      const hasExact = userPerms.includes(perm);
85	      const hasWildcard = userPerms.some(p => {
86	        if (p.endsWith('.*')) {
87	          const prefix = p.slice(0, -1);
88	          return perm.startsWith(prefix);
89	        }
90	        return false;
91	      });
92	      if (!hasExact && !hasWildcard) {
93	        throw Errors.forbidden(`Missing permission: ${perm}`);
94	      }
95	    }
96	  };
97	}
98	
99	export function requireScope(scopeType, getScopeId) {
100	  return async (request, reply) => {
101	    if (!request.user) throw Errors.authRequired();
102	    const userPerms = request.user.permissions;
103	    if (userPerms.some(p => p === 'admin.*')) return;
104	
105	    const userScopes = request.user.scopes;
106	    // Users with NO scope entries at all are unrestricted (not scope-limited)
107	    if (!userScopes || userScopes.length === 0) return;
108	
109	    const relevantScopes = userScopes.filter(s => s.scope_type === scopeType);
110	    // User has scopes but none of this type — they are a scoped user
111	    // without access to this scope dimension. DEFAULT DENY.
112	    if (relevantScopes.length === 0) {
113	      throw Errors.scopeDenied();
114	    }
115	
116	    const scopeId = typeof getScopeId === 'function' ? getScopeId(request) : request.params[getScopeId];
117	    // If we can't determine the scope ID, default DENY for scoped users
118	    if (!scopeId) {
119	      throw Errors.scopeDenied();
120	    }
121	
122	    const hasScope = relevantScopes.some(s => s.scope_id === scopeId);
123	    if (!hasScope) {
124	      throw Errors.scopeDenied();
125	    }
126	  };
127	}
128	
129	export function getScopeFilter(user, scopeType) {
130	  if (!user) return null;
131	  if (user.permissions.some(p => p === 'admin.*')) return null;
132	  // If user has ANY scopes at all, they are a scoped user
133	  if (!user.scopes || user.scopes.length === 0) return null; // truly unrestricted
134	  const scopes = user.scopes.filter(s => s.scope_type === scopeType);
135	  // User is scoped but not in this dimension — return empty array (deny all)
136	  if (scopes.length === 0) return [];
137	  return scopes.map(s => s.scope_id);
138	}
139	
140	export async function resolveWarehouseScope(user) {
141	  // Direct warehouse scope — only use if user actually HAS warehouse scopes
142	  const warehouseScope = getScopeFilter(user, 'warehouse');
143	  if (warehouseScope && warehouseScope.length > 0) return warehouseScope;
144	
145	  // Resolve store scope → warehouse IDs via mapping table
146	  const storeScope = getScopeFilter(user, 'store');
147	  if (storeScope && storeScope.length > 0) {
148	    const { query } = await import('../db/pool.js');
149	    const result = await query(
150	      'SELECT DISTINCT warehouse_id FROM store_warehouses WHERE store_id = ANY($1)',
151	      [storeScope]
152	    );
153	    if (result.rows.length > 0) {
154	      return result.rows.map(r => r.warehouse_id);
155	    }
156	    return []; // store scoped but no warehouse mapping = deny
157	  }
158	
159	  // User has scopes (warehouseScope is []) but no warehouse or store scopes → deny
160	  if (warehouseScope !== null || storeScope !== null) return [];
161	
162	  return null; // truly unrestricted
163	}
