6	/**
7	 * Centralized department scope check for outcomes.
8	 * Policy: if user has department scopes, ALL linked project departments must be in scope.
9	 * Outcomes with no linked projects are denied to scoped users.
10	 */
11	function enforceOutcomeDepartmentScope(departmentFilter, linkedDepts) {
12	  if (!departmentFilter) return; // admins / unscoped users pass through
13	  // Deny if any linked project has null department
14	  if (linkedDepts.some(d => !d)) {
15	    throw Errors.scopeDenied();
16	  }
17	  if (linkedDepts.length === 0 || !linkedDepts.every(dId => departmentFilter.includes(dId))) {
18	    throw Errors.scopeDenied();
19	  }
20	}
21	
22	export default async function outcomesRoutes(fastify) {
23	  fastify.get('/api/outcomes', {
24	    preHandler: [authenticate, requirePermission('outcomes.*')],
25	  }, async (request) => {
26	    const departmentFilter = getScopeFilter(request.user, 'department');
27	    const outcomes = await outcomesService.listOutcomes(request.query, departmentFilter);
28	    return { success: true, data: outcomes };
29	  });
30	
