32	    preHandler: [authenticate, requirePermission('outcomes.*')],
33	  }, async (request) => {
34	    const outcome = await outcomesService.getOutcome(request.params.id);
35	    const departmentFilter = getScopeFilter(request.user, 'department');
36	    enforceOutcomeDepartmentScope(departmentFilter, (outcome.projects || []).map(p => p.department_id));
37	    return { success: true, data: outcome };
38	  });
39	
40	  fastify.post('/api/outcomes', {
41	    preHandler: [authenticate, requirePermission('outcomes.*')],
42	    schema: {
43	      body: {
44	        type: 'object',
45	        required: ['type', 'title', 'projects'],
46	        properties: {
47	          type: { type: 'string', enum: ['study', 'patent', 'award', 'copyright'] },
48	          title: { type: 'string', minLength: 1 },
49	          certificate_number: { type: 'string' },
50	          description: { type: 'string' },
51	          projects: {
52	            type: 'array',
53	            minItems: 1,
54	            items: {
55	              type: 'object',
56	              required: ['project_id', 'contribution_share'],
57	              properties: {
58	                project_id: { type: 'string' },
59	                contribution_share: { type: 'number', minimum: 0.01, maximum: 100 },
60	              },
61	            },
62	          },
63	        },
64	      },
65	    },
66	  }, async (request, reply) => {
67	    // Verify department scope BEFORE creation
68	    const departmentFilter = getScopeFilter(request.user, 'department');
69	    if (departmentFilter) {
70	      if (!request.body.projects || request.body.projects.length === 0) {
71	        throw Errors.validation('Scoped users must link at least one project to an outcome');
72	      }
73	      const projectIds = request.body.projects.map(p => p.project_id).filter(Boolean);
74	      if (projectIds.length > 0) {
75	        const projectsResult = await query(
76	          'SELECT id, department_id FROM projects WHERE id = ANY($1)',
77	          [projectIds]
78	        );
79	        const nullDeptProjects = projectsResult.rows.filter(p => !p.department_id);
80	        if (nullDeptProjects.length > 0) {
81	          throw Errors.validation('All linked projects must have a department_id for scoped users');
82	        }
83	        const linkedDepts = projectsResult.rows.map(p => p.department_id);
84	        if (!linkedDepts.every(dId => departmentFilter.includes(dId))) {
85	          throw Errors.scopeDenied();
86	        }
87	      }
88	    }
89	    const result = await outcomesService.createOutcome(request.body, request.user.id);
90	    reply.code(201);
91	    return { success: true, data: result };
92	  });
93	
94	  fastify.put('/api/outcomes/:id', {
95	    preHandler: [authenticate, requirePermission('outcomes.*')],
96	  }, async (request) => {
97	    const departmentFilter = getScopeFilter(request.user, 'department');
98	    // Check scope on existing linked projects
99	    const existing = await outcomesService.getOutcome(request.params.id);
100	    enforceOutcomeDepartmentScope(departmentFilter, (existing.projects || []).map(p => p.department_id));
101	    // Also validate incoming project links against scope
102	    if (departmentFilter && request.body.projects && request.body.projects.length > 0) {
103	      const incomingProjectIds = request.body.projects.map(p => p.project_id).filter(Boolean);
104	      if (incomingProjectIds.length > 0) {
