1	import { writable, get } from 'svelte/store';
2	
3	let currentUserId = null;
4	
5	function getQueueKey() {
6	  return currentUserId ? `petmed_mutation_queue_${currentUserId}` : null;
7	}
8	
9	export const pendingMutations = writable(0);
10	
11	// Operations that must NOT be queued (require real-time consistency)
12	const NON_QUEUEABLE = [
13	  '/cart/checkout', '/holds/', '/tasks/', '/auth/',
14	];
15	
16	function isQueueable(path) {
17	  return !NON_QUEUEABLE.some(p => path.includes(p));
18	}
19	
20	function loadQueue() {
21	  const key = getQueueKey();
22	  if (!key) return [];
23	  try { return JSON.parse(localStorage.getItem(key) || '[]'); }
24	  catch { return []; }
25	}
26	
27	function saveQueue(queue) {
28	  const key = getQueueKey();
29	  if (!key) return;
30	  localStorage.setItem(key, JSON.stringify(queue));
31	  pendingMutations.set(queue.length);
32	}
33	
34	export function setQueueUser(userId) {
35	  currentUserId = userId;
36	  if (userId) {
37	    pendingMutations.set(loadQueue().length);
38	  }
39	}
40	
41	export function clearUserQueue() {
42	  const key = getQueueKey();
43	  if (key) localStorage.removeItem(key);
44	  currentUserId = null;
45	  pendingMutations.set(0);
46	}
47	
48	export function queueMutation(method, path, body) {
49	  if (!currentUserId) {
50	    throw new Error('Cannot queue mutations: no user session');
51	  }
52	  if (!isQueueable(path)) {
53	    throw new Error(`Cannot queue offline: ${path} requires backend confirmation`);
54	  }
55	  const queue = loadQueue();
56	  queue.push({
57	    id: `${Date.now()}-${Math.random().toString(36).slice(2)}`,
58	    method, path, body,
59	    createdAt: new Date().toISOString(),
60	  });
61	  saveQueue(queue);
62	}
63	
64	export async function flushMutationQueue() {
65	  const queue = loadQueue();
66	  if (queue.length === 0) return { flushed: 0, failed: 0 };
67	
68	  let flushed = 0;
69	  let failed = 0;
70	  const remaining = [];
71	
72	  for (const entry of queue) {
73	    try {
74	      const response = await fetch(`/api${entry.path}`, {
75	        method: entry.method,
76	        headers: { 'Content-Type': 'application/json' },
77	        credentials: 'include',
78	        body: entry.body ? JSON.stringify(entry.body) : undefined,
79	      });
80	      if (response.ok) {
81	        flushed++;
82	      } else if (response.status === 409) {
83	        const data = await response.json().catch(() => ({}));
