253	export async function commitImport(importSessionId, userId, requestingUser = null) {
254	  const session = await query(
255	    "SELECT * FROM import_sessions WHERE id = $1 AND status = 'validated'",
256	    [importSessionId]
257	  );
258	  if (session.rows.length === 0) throw Errors.notFound('Import session');
259	
260	  const importSession = session.rows[0];
261	
262	  // Verify the import session belongs to the calling user (or caller is admin)
263	  if (requestingUser) {
264	    const isAdmin = requestingUser.permissions && requestingUser.permissions.some(p => p === 'admin.*');
265	    if (!isAdmin && importSession.user_id !== requestingUser.id) {
266	      throw Errors.forbidden('You can only commit your own import sessions');
267	    }
268	  }
269	  const validRows = typeof importSession.valid_rows === 'string'
270	    ? JSON.parse(importSession.valid_rows) : importSession.valid_rows;
271	
272	  if (validRows.length === 0) throw Errors.validation('No valid rows to import');
273	
274	  let imported = 0;
275	  const commitErrors = [];
276	
277	  await transaction(async (client) => {
278	    for (const row of validRows) {
279	      try {
280	        await commitRow(client, importSession.type, row.data);
281	        imported++;
282	      } catch (err) {
283	        commitErrors.push({
284	          row: row.row,
285	          data: row.data,
286	          error: err.message || 'Unknown commit error',
287	        });
288	      }
289	    }
290	
291	    await client.query(
292	      "UPDATE import_sessions SET status = 'committed' WHERE id = $1",
293	      [importSessionId]
294	    );
295	  });
296	
297	  await logAudit(userId, 'import_committed', 'import_session', importSessionId,
298	    { type: importSession.type, imported, skipped: commitErrors.length }, null);
299	
300	  return { imported_count: imported, skipped_count: commitErrors.length, commit_errors: commitErrors };
