104	export async function assignTask(taskId, assignedUserId) {
105	  return transaction(async (client) => {
106	    const taskResult = await client.query(
107	      'SELECT * FROM tasks WHERE id = $1 FOR UPDATE', [taskId]
108	    );
109	    if (taskResult.rows.length === 0) throw Errors.notFound('Task');
110	    const task = taskResult.rows[0];
111	
112	    if (task.status !== 'open') {
113	      throw Errors.conflict(`Task cannot be assigned (current status: ${task.status})`);
114	    }
115	
116	    // Validate assignee exists and is active
117	    const assigneeResult = await client.query(
118	      'SELECT id, status FROM users WHERE id = $1',
119	      [assignedUserId]
120	    );
121	    if (assigneeResult.rows.length === 0) {
122	      throw Errors.notFound('Assignee user not found');
123	    }
124	    if (assigneeResult.rows[0].status !== 'active') {
125	      throw Errors.validation('Assignee user is not active');
126	    }
127	
128	    // Check assignee has task.* or admin.* permission via role lookup
129	    const rolePerms = await client.query(
130	      `SELECT r.permissions FROM roles r
131	       JOIN user_roles ur ON ur.role_id = r.id
132	       WHERE ur.user_id = $1`,
133	      [assignedUserId]
134	    );
135	    const allPerms = rolePerms.rows.flatMap(r => r.permissions || []);
136	    const hasTaskPerm = allPerms.some(p => p === 'task.*' || p === 'admin.*');
137	    if (!hasTaskPerm) {
138	      throw Errors.validation('Assignee does not have dispatch capability');
139	    }
140	
141	    // If task has a warehouse, check assignee has access to that warehouse
142	    if (task.warehouse_id) {
143	      const assigneeScopes = await client.query(
144	        'SELECT scope_type, scope_id FROM user_scopes WHERE user_id = $1',
145	        [assignedUserId]
146	      );
147	      const scopes = assigneeScopes.rows;
148	      // If assignee has scopes at all, check warehouse access
149	      if (scopes.length > 0) {
150	        const warehouseScopes = scopes.filter(s => s.scope_type === 'warehouse').map(s => s.scope_id);
151	        const storeScopes = scopes.filter(s => s.scope_type === 'store').map(s => s.scope_id);
152	
153	        let hasWarehouseAccess = false;
154	        if (warehouseScopes.includes(task.warehouse_id)) {
155	          hasWarehouseAccess = true;
156	        } else if (storeScopes.length > 0) {
157	          // Resolve store → warehouse mapping
158	          const mapping = await client.query(
159	            'SELECT warehouse_id FROM store_warehouses WHERE store_id = ANY($1)',
160	            [storeScopes]
161	          );
162	          hasWarehouseAccess = mapping.rows.some(r => r.warehouse_id === task.warehouse_id);
163	        } else if (warehouseScopes.length === 0 && storeScopes.length === 0) {
164	          hasWarehouseAccess = true; // No scope restrictions = unrestricted
165	        }
166	
167	        if (!hasWarehouseAccess) {
168	          throw Errors.validation('Assignee is not in scope for this task\'s warehouse');
169	        }
170	      }
171	    }
172	
173	    // Proceed with assignment
174	    await client.query(
175	      `UPDATE tasks SET status = 'assigned', assigned_user_id = $1,
176	       version = version + 1, updated_at = NOW() WHERE id = $2`,
177	      [assignedUserId, taskId]
178	    );
