234	export async function updateTaskStatus(taskId, userId, newStatus) {
235	  return transaction(async (client) => {
236	    const taskResult = await client.query(
237	      'SELECT * FROM tasks WHERE id = $1 FOR UPDATE',
238	      [taskId]
239	    );
240	    if (taskResult.rows.length === 0) throw Errors.notFound('Task');
241	    const task = taskResult.rows[0];
242	
243	    const validTransitions = {
244	      accepted: ['in_progress', 'cancelled'],
245	      in_progress: ['completed', 'failed', 'cancelled'],
246	      assigned: ['cancelled'],
247	      open: ['cancelled'],
248	    };
249	
250	    const allowed = validTransitions[task.status] || [];
251	    if (!allowed.includes(newStatus)) {
252	      throw Errors.validation(`Cannot transition from ${task.status} to ${newStatus}`);
253	    }
254	
255	    await client.query(
256	      `UPDATE tasks SET status = $1, version = version + 1, updated_at = NOW() WHERE id = $2`,
257	      [newStatus, taskId]
258	    );
259	
260	    await client.query(
261	      'INSERT INTO task_history (task_id, user_id, action) VALUES ($1, $2, $3)',
262	      [taskId, userId, newStatus]
263	    );
264	
265	    if (newStatus === 'completed' || newStatus === 'failed' || newStatus === 'cancelled') {
266	      await client.query(
267	        `UPDATE worker_metrics SET active_task_count = GREATEST(0, active_task_count - 1),
268	         last_computed_at = NOW() WHERE user_id = $1`,
269	        [task.assigned_user_id || userId]
270	      );
271	
272	      if (newStatus === 'completed') {
273	        await client.query(
274	          `UPDATE worker_metrics SET completed_count = completed_count + 1,
275	           last_computed_at = NOW() WHERE user_id = $1`,
276	          [task.assigned_user_id || userId]
277	        );
278	      }
279	      if (newStatus === 'failed') {
280	        await client.query(
281	          `UPDATE worker_metrics SET failed_count = failed_count + 1,
282	           last_computed_at = NOW() WHERE user_id = $1`,
283	          [task.assigned_user_id || userId]
284	        );
285	      }
286	
287	      // Reconcile inventory for THIS TASK's allocations only (not the whole order).
288	      // task.order_line_ids contains the specific order lines owned by this task.
289	      const rawLineIds = task.order_line_ids;
290	      const taskLineIds = Array.isArray(rawLineIds)
291	        ? rawLineIds
292	        : (typeof rawLineIds === 'string' ? JSON.parse(rawLineIds) : []);
293	
294	      if (taskLineIds.length > 0) {
295	        if (newStatus === 'completed') {
296	          // Completed: convert reserved → consumed (reduce both available_qty and reserved_qty)
297	          const allocs = await client.query(
298	            `SELECT ola.inventory_id, ola.quantity
299	             FROM order_line_allocations ola
300	             WHERE ola.order_line_id = ANY($1::uuid[])`,
301	            [taskLineIds]
302	          );
303	          for (const alloc of allocs.rows) {
304	            await client.query(
305	              `UPDATE inventory SET available_qty = available_qty - $1,
306	               reserved_qty = GREATEST(0, reserved_qty - $1), updated_at = NOW()
307	               WHERE id = $2`,
308	              [alloc.quantity, alloc.inventory_id]
309	            );
310	          }
311	        } else if (newStatus === 'cancelled' || newStatus === 'failed') {
312	          // Cancelled/failed: release only this task's reservations
313	          const allocs = await client.query(
314	            `SELECT ola.inventory_id, ola.quantity
315	             FROM order_line_allocations ola
316	             WHERE ola.order_line_id = ANY($1::uuid[])`,
317	            [taskLineIds]
318	          );
319	          for (const alloc of allocs.rows) {
320	            await client.query(
321	              `UPDATE inventory SET reserved_qty = GREATEST(0, reserved_qty - $1),
322	               updated_at = NOW() WHERE id = $2`,
323	              [alloc.quantity, alloc.inventory_id]
324	            );
325	          }
326	        }
327	      }
328	    }
329	
330	    await logAudit(userId, `task_${newStatus}`, 'task', taskId, {}, null);
331	
332	    return getTask(taskId);
333	  });
