10	export function checkDuplicateWarnings(title, certNumber, existingOutcomes) {
11	  const warnings = [];
12	  const normalizedTitle = normalizeText(title);
13	  const normalizedCert = certNumber ? normalizeText(certNumber) : null;
14	
15	  for (const existing of existingOutcomes) {
16	    const existingTitle = normalizeText(existing.title);
17	    if (existingTitle === normalizedTitle) {
18	      warnings.push({ field: 'title', match_type: 'exact', existing_id: existing.id, existing_title: existing.title });
19	    } else if (trigramSimilarity(normalizedTitle, existingTitle) > 0.6) {
20	      warnings.push({ field: 'title', match_type: 'near', existing_id: existing.id, existing_title: existing.title });
21	    }
22	
23	    if (normalizedCert && existing.certificate_number_encrypted) {
24	      const existingCert = normalizeText(decrypt(existing.certificate_number_encrypted) || '');
25	      if (existingCert === normalizedCert) {
26	        warnings.push({ field: 'certificate_number', match_type: 'exact', existing_id: existing.id, existing_title: existing.title });
27	      } else if (trigramSimilarity(normalizedCert, existingCert) > 0.7) {
28	        warnings.push({ field: 'certificate_number', match_type: 'near', existing_id: existing.id, existing_title: existing.title });
29	      }
30	    }
31	  }
32	
33	  return warnings;
34	}
