41	export function trigramSimilarity(a, b) {
42	  if (!a || !b) return 0;
43	  const trigramsA = getTrigrams(a);
44	  const trigramsB = getTrigrams(b);
45	  if (trigramsA.size === 0 && trigramsB.size === 0) return 1;
46	  if (trigramsA.size === 0 || trigramsB.size === 0) return 0;
47	
48	  let intersection = 0;
49	  for (const t of trigramsA) {
50	    if (trigramsB.has(t)) intersection++;
51	  }
52	  return intersection / Math.max(trigramsA.size, trigramsB.size);
53	}
