55	function getTrigrams(str) {
56	  const trigrams = new Set();
57	  const padded = `  ${str} `;
58	  for (let i = 0; i < padded.length - 2; i++) {
59	    trigrams.add(padded.substring(i, i + 3));
60	  }
61	  return trigrams;
62	}
