48	export function queueMutation(method, path, body) {
49	  if (!currentUserId) {
50	    throw new Error('Cannot queue mutations: no user session');
51	  }
52	  if (!isQueueable(path)) {
53	    throw new Error(`Cannot queue offline: ${path} requires backend confirmation`);
54	  }
55	  const queue = loadQueue();
56	  queue.push({
57	    id: `${Date.now()}-${Math.random().toString(36).slice(2)}`,
58	    method, path, body,
59	    createdAt: new Date().toISOString(),
60	  });
61	  saveQueue(queue);
62	}
