64	export async function flushMutationQueue() {
65	  const queue = loadQueue();
66	  if (queue.length === 0) return { flushed: 0, failed: 0 };
67	
68	  let flushed = 0;
69	  let failed = 0;
70	  const remaining = [];
71	
72	  for (const entry of queue) {
73	    try {
74	      const response = await fetch(`/api${entry.path}`, {
75	        method: entry.method,
76	        headers: { 'Content-Type': 'application/json' },
77	        credentials: 'include',
78	        body: entry.body ? JSON.stringify(entry.body) : undefined,
79	      });
80	      if (response.ok) {
81	        flushed++;
82	      } else if (response.status === 409) {
83	        const data = await response.json().catch(() => ({}));
84	        if (data.error?.code === 'DUPLICATE') {
85	          flushed++; // Idempotent duplicate — already applied
86	        } else {
87	          failed++;
88	          remaining.push(entry);
89	        }
90	      } else {
91	        failed++;
92	        remaining.push(entry);
93	      }
94	    } catch {
95	      failed++;
96	      remaining.push(entry);
97	    }
98	  }
99	
100	  saveQueue(remaining);
101	  return { flushed, failed };
102	}
103	
104	// Auto-flush when coming back online
105	if (typeof window !== 'undefined') {
106	  window.addEventListener('online', () => {
107	    const q = loadQueue();
108	    if (q.length > 0) flushMutationQueue();
109	  });
110	}
