43	export async function mutationWithFallback(method, path, body) {
44	  try {
45	    const response = await fetch(`/api${path}`, {
46	      method: method.toUpperCase(),
47	      headers: { 'Content-Type': 'application/json' },
48	      credentials: 'include',
49	      body: body ? JSON.stringify(body) : undefined,
50	    });
51	    if (!response.ok) {
52	      const data = await response.json().catch(() => ({}));
53	      const err = new Error(data.error?.message || response.statusText);
54	      err.code = data.error?.code;
55	      err.status = response.status;
56	      throw err;
57	    }
58	    return await response.json();
59	  } catch (err) {
60	    if (err.status) throw err; // Server responded with error — don't queue
61	    // Network error — queue if allowed
62	    const { queueMutation } = await import('./mutationQueue.js');
63	    queueMutation(method.toUpperCase(), path, body);
64	    return { queued: true, message: 'Saved offline — will sync when connected' };
65	  }
66	}
