1	import { writable, get } from 'svelte/store';
2	import { isQueueableMutation } from './offlineMutationPolicy.js';
3	
4	let currentUserId = null;
5	
6	function getQueueKey() {
7	  return currentUserId ? `petmed_mutation_queue_${currentUserId}` : null;
8	}
9	
10	export const pendingMutations = writable(0);
11	
12	function loadQueue() {
13	  const key = getQueueKey();
14	  if (!key) return [];
15	  try { return JSON.parse(localStorage.getItem(key) || '[]'); }
16	  catch { return []; }
17	}
18	
19	function saveQueue(queue) {
20	  const key = getQueueKey();
21	  if (!key) return;
22	  localStorage.setItem(key, JSON.stringify(queue));
23	  pendingMutations.set(queue.length);
24	}
25	
26	export function setQueueUser(userId) {
27	  currentUserId = userId;
28	  if (userId) {
29	    pendingMutations.set(loadQueue().length);
30	  }
31	}
32	
33	export function clearUserQueue() {
34	  const key = getQueueKey();
35	  if (key) localStorage.removeItem(key);
36	  currentUserId = null;
37	  pendingMutations.set(0);
38	}
39	
40	export function queueMutation(method, path, body) {
41	  if (!currentUserId) {
42	    throw new Error('Cannot queue mutations: no user session');
43	  }
44	  if (!isQueueableMutation(method, path)) {
45	    throw new Error(`Cannot queue offline: ${method} ${path} requires backend confirmation`);
46	  }
47	  const queue = loadQueue();
48	  queue.push({
49	    id: `${Date.now()}-${Math.random().toString(36).slice(2)}`,
50	    method, path, body,
51	    createdAt: new Date().toISOString(),
52	  });
53	  saveQueue(queue);
54	}
55	
56	export async function flushMutationQueue() {
57	  const queue = loadQueue();
58	  if (queue.length === 0) return { flushed: 0, failed: 0 };
59	
60	  let flushed = 0;
61	  let failed = 0;
62	  const remaining = [];
63	
64	  for (const entry of queue) {
65	    try {
66	      const response = await fetch(`/api${entry.path}`, {
67	        method: entry.method,
68	        headers: { 'Content-Type': 'application/json' },
69	        credentials: 'include',
70	        body: entry.body ? JSON.stringify(entry.body) : undefined,
71	      });
72	      if (response.ok) {
73	        flushed++;
74	      } else if (response.status === 409) {
75	        const data = await response.json().catch(() => ({}));
76	        if (data.error?.code === 'DUPLICATE') {
77	          flushed++; // Idempotent duplicate — already applied
78	        } else {
79	          failed++;
80	          remaining.push(entry);
81	        }
82	      } else {
83	        failed++;
84	        remaining.push(entry);
85	      }
86	    } catch {
87	      failed++;
88	      remaining.push(entry);
89	    }
90	  }
91	
92	  saveQueue(remaining);
93	  return { flushed, failed };
94	}
95	
96	// Auto-flush when coming back online
97	if (typeof window !== 'undefined') {
98	  window.addEventListener('online', () => {
99	    const q = loadQueue();
100	    if (q.length > 0) flushMutationQueue();
101	  });
102	}
