1	import { api } from './api.js';
2	import { cacheGet, cacheSet } from './cache.js';
3	import { writable } from 'svelte/store';
4	import { isQueueableMutation } from './offlineMutationPolicy.js';
5	
6	export const isOnline = writable(true);
7	
8	if (typeof window !== 'undefined') {
9	  window.addEventListener('online', () => isOnline.set(true));
10	  window.addEventListener('offline', () => isOnline.set(false));
11	}
12	
13	export async function cachedGet(path, cacheKey, ttlMs = 5 * 60 * 1000) {
14	  // Try network first
15	  try {
16	    const result = await api.get(path);
17	    cacheSet(cacheKey || path, result, ttlMs);
18	    isOnline.set(true);
19	    return result;
20	  } catch (err) {
21	    // If network fails, try cache
22	    const cached = cacheGet(cacheKey || path);
23	    if (cached) {
24	      isOnline.set(false);
25	      return cached;
26	    }
27	    throw err;
28	  }
29	}
30	
31	/**
32	 * Custom error for mutations rejected because the device is offline
33	 * and the operation is not safe to defer.
34	 */
35	export class OfflineError extends Error {
36	  constructor(message) {
37	    super(message || 'You are offline. This action requires an active connection.');
38	    this.name = 'OfflineError';
39	    this.code = 'OFFLINE';
40	    this.offline = true;
41	  }
42	}
43	
44	export async function mutationWithFallback(method, path, body) {
45	  try {
46	    const response = await fetch(`/api${path}`, {
47	      method: method.toUpperCase(),
48	      headers: { 'Content-Type': 'application/json' },
49	      credentials: 'include',
50	      body: body ? JSON.stringify(body) : undefined,
51	    });
52	    if (!response.ok) {
53	      const data = await response.json().catch(() => ({}));
54	      const err = new Error(data.error?.message || response.statusText);
55	      err.code = data.error?.code;
56	      err.status = response.status;
57	      throw err;
58	    }
59	    return await response.json();
60	  } catch (err) {
61	    if (err.status) throw err; // Server responded with error — don't queue
62	    // Network error — only queue if policy allows it
63	    if (!isQueueableMutation(method, path)) {
64	      throw new OfflineError(`Cannot perform ${method.toUpperCase()} ${path} offline — requires server confirmation`);
65	    }
66	    const { queueMutation } = await import('./mutationQueue.js');
67	    queueMutation(method.toUpperCase(), path, body);
68	    return { queued: true, message: 'Saved offline — will sync when connected' };
69	  }
70	}
